INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('judicial-57f41407-moex-00073', 'judicial-57f41407', 'judicial-57f41407-moex-114-34c7f7f6', 'sub-judicial-57f41407-02', NULL, 'single_choice', '「藝術的生活，原是觀照享樂的生活。凡為實利或成見束縛，不能把日常生活咀嚼玩味的，都是與藝 術無緣的人們。真的藝術不限在詩裡或畫裡，到處都有，隨時可得。能捕捉後用文字表現的是詩人， 用形及五彩表現的是畫家。不會作詩作畫也不要緊，只要對日常生活有觀照玩味的能力，無論誰都能 享受藝術之神的恩寵。否則雖自號為詩人畫家，仍是俗物。」 根據上文，下列選項最符合文意的是：', '["人們在實利與成見的影響下，反而可激盪出更多靈感", "如果能懂得作詩作畫，對於生活玩味品賞的助益更大", "受到藝術之神恩寵的人，正是能夠觀照玩味生活的人", "詩人或畫家能觀照到日常生活以外的世界，方可脫俗"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:36+00:00", "source_pdf_sha1": "16c911fc4062", "answer_pdf_sha1": "ac5dd4608ec6", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "301", "s": "0103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00074', 'judicial-57f41407', 'judicial-57f41407-moex-114-34c7f7f6', 'sub-judicial-57f41407-02', NULL, 'single_choice', '「音樂創作向來是當下社會現象的反饋。近來各種創作形式席捲全球，音樂變得好似只是媒介，不再 敘說完整故事；演出者可以是虛擬歌手，沒有人在意背後是否真實；創作者不用本名，也不用露臉， 就可以創造未來。不過回到創作面，還是要有自己相信的核心價值，並不能全然被新的技術影響。是 以新世代音樂人的路，會比舊世代寬廣許多，唯有保持開放的心態，不安於現狀，才能在創作形式不 斷轉變下詮釋時代，並且開創新的價值。」 根據上文，有關「音樂創作」的敘述，下列何者最符合文意？', '["用音樂的新形式，創造虛擬的新價值", "音樂只是媒介，重點在於如何說故事", "放下傳統的束縛，全面展開嶄新的音樂形式", "關注發生的各種現象，但不該被新形式綁架"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:36+00:00", "source_pdf_sha1": "16c911fc4062", "answer_pdf_sha1": "ac5dd4608ec6", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "301", "s": "0103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00075', 'judicial-57f41407', 'judicial-57f41407-moex-114-34c7f7f6', 'sub-judicial-57f41407-02', NULL, 'single_choice', '下列選項，何者不是以茶的滋味比喻人生？', '["喝茶當於瓦屋紙窗之下，用素雅的陶瓷茶具，同二三人共飲，得半日之閒", "榮華或清苦，都像第一遍茶，切記倒掉，而濃茶轉淡，飲到路斷夢斷，自然回甘", "茶則經他的手澤撫摸，「茶，則也。」對他訴說喝茶的一生，其實是在濃淡冷暖中喝自己的規矩而已", "我之飲茶，並非慢慢啜飲，往往都是舉起杯來，一飲而盡，只在試試精神上有無接受人生艱苦的勇 氣，能否毫不猶豫地飲盡人生的杯底"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:36+00:00", "source_pdf_sha1": "16c911fc4062", "answer_pdf_sha1": "ac5dd4608ec6", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "301", "s": "0103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00076', 'judicial-57f41407', 'judicial-57f41407-moex-114-34c7f7f6', 'sub-judicial-57f41407-02', NULL, 'single_choice', '「我這輩人用冰箱，常是多買了什麼、拿了什麼塞進冰箱就忘了，只等著掃除時一個個清出、一次次 懺悔：吃進去的是熱量，冰起來的是薪水。」 根據上文，作者描寫「我這輩人」的冰箱是用於：', '["滿足口腹之慾", "遺忘存放之物", "保存食物的新鮮", "善用薪水維護健康"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:36+00:00", "source_pdf_sha1": "16c911fc4062", "answer_pdf_sha1": "ac5dd4608ec6", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "301", "s": "0103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00077', 'judicial-57f41407', 'judicial-57f41407-moex-114-34c7f7f6', 'sub-judicial-57f41407-02', NULL, 'single_choice', '「若我能在落筆寫詩的能力與詩歌想像的狂喜間抉擇，我會選擇想像，那才是真正的好詩，但一般人 可能會認為——我的選擇向來錯得離譜。」 根據上文，下列選項何者正確？', '["想像力和是不是能創作出好詩沒有關聯", "作者謙虛認為自己缺乏落筆寫詩的能力", "關於詩創作，多數人和作者的立場一致", "作者認為能馳騁無限想像才能創作好詩"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:36+00:00", "source_pdf_sha1": "16c911fc4062", "answer_pdf_sha1": "ac5dd4608ec6", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "301", "s": "0103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00078', 'judicial-57f41407', 'judicial-57f41407-moex-114-34c7f7f6', 'sub-judicial-57f41407-02', NULL, 'single_choice', '「當我們邁開步伐走路，新聞就不再有任何重要性。這裡是指那種為時好幾天、甚至好幾星期的長途 健行。不久，我們不再看到人間煙火，遠離了那些嘈雜騷動，不再知道某某事件的最新發展。我們不 再急著掌握事件轉折，不再想著發掘它如何開始，不再等著知道它如何結束。『你知道那件事後來怎 麼樣嗎？』不，一旦邁開步伐，這一切就不再重要了。置身於絕對的永恆中，我們全然脫離平常那些 稍縱即逝、卻令人屏息的新聞。」 根據上文，下列選項何者最符合文意？', '["長途健行可以使我們身心平衡，才能面對各種紛繁的新聞事件", "長途健行幫助我們遠離紛擾，獲得寧靜及放鬆，進而體會永恆", "人都有好奇心，對新聞事件的關心，就算步行外出也難以忘懷", "人要走出戶外，就能切斷來自現實的壓力，避免盲目追逐潮流"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:36+00:00", "source_pdf_sha1": "16c911fc4062", "answer_pdf_sha1": "ac5dd4608ec6", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "301", "s": "0103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00079', 'judicial-57f41407', 'judicial-57f41407-moex-114-34c7f7f6', 'sub-judicial-57f41407-02', NULL, 'single_choice', '「流行趨勢的調查都是為了探知未來可能發生的結果，並使創造產品的設計師與提供服務的業者受益。 大家常在討論趨勢預測導致風格同質性或遏止創意的問題，但每個設計師和企業都是獨立的，他們都 需要用不同方式解讀我們提供的訊息，找到和他們的消費者相關的切入點，只要在這樣的前提下，個 人創意就不會被設限。」 根據上文，下列選項何者正確？', '["多數消費者仍會受趨勢預測，改變其購買行為", "趨勢預測雖有其益處，但整體說來仍弊大於利", "流行趨勢調查以不同方式解讀，有助於避免創意受限", "企業根據市場需求調查，即可降低風格同質性的危機"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:36+00:00", "source_pdf_sha1": "16c911fc4062", "answer_pdf_sha1": "ac5dd4608ec6", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "301", "s": "0103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00080', 'judicial-57f41407', 'judicial-57f41407-moex-114-34c7f7f6', 'sub-judicial-57f41407-02', NULL, 'single_choice', '「農業部林業及自然保育署（以下簡稱林務署）著手建置全國步道系統，將銅山的臺灣山毛櫸林規劃為特 色步道。以老少咸宜的大眾路線為定線考量，捨棄能更快抵達的稜線捷徑，選擇另開下切的新路徑，串連 起大元山林場山地運材軌道路跡與臺灣山毛櫸所在的山稜，並設多面自導式解說牌，介紹沿途的自然生 態及人文史跡。藉著拉近大眾跟山毛櫸之間的距離，亦可增加民眾對於該物種的保育意識。」 根據上文，下列選項何者最符合文意？', '["此特色步道的開發使得往返的路程更快速便利", "銅山步道的新路徑以開發運輸木材軌道為主要功能", "此特色步道的開發以觀光與教育做為規劃的核心理念", "大元山林場山地運材軌道路跡是林務署於21世紀所建置"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:36+00:00", "source_pdf_sha1": "16c911fc4062", "answer_pdf_sha1": "ac5dd4608ec6", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "301", "s": "0103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00081', 'judicial-57f41407', 'judicial-57f41407-moex-114-34c7f7f6', 'sub-judicial-57f41407-02', NULL, 'single_choice', '「至今我仍常想念起劍橋大學的總圖書館，過多的藏書量，使書架必須以一種接近極限的密度 排立——上頂天、下貼地，間隔走道須側身。孤獨的研究者穿梭在這座巨型迷宮，必須轉動書架旁的 計時器，微弱燈光才短暫喚醒無人聞問的書們。書架始終是書最忠實的守候。它牢靠地支撐起書，又 如此宿命地扮演配角。因為人們在意的，從來不是書架，而是填充它的書。」 根據上文，作者對於「書架」的觀察，正確的敘述是：', '["人們最在意書架上是否擺出了最受矚目的作品", "在書架旁放計時器是為了管制龐大讀者的流量", "書架排成迷宮的樣子可以增加讀者閱讀的趣味", "書架的宿命是必須不斷承受書本填充時的擠壓"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:36+00:00", "source_pdf_sha1": "16c911fc4062", "answer_pdf_sha1": "ac5dd4608ec6", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "301", "s": "0103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00082', 'judicial-57f41407', 'judicial-57f41407-moex-114-34c7f7f6', 'sub-judicial-57f41407-02', NULL, 'single_choice', '「2014年，藉由KeepWalking夢想資助計畫的支持，曾文勤創辦全臺第一個『街遊』導覽活動，讓街 友化身為導覽員，帶領民眾用不同的角度重新認識臺北。五年後，街遊活動推出至累積參與人次超過 9,000人，翻轉社會大眾對無家者的既定印象，參與者以年輕與女性族群居多。『起家工作室』專案， 則讓擁有修繕技能的無家者師傅幫助弱勢家戶改善居住空間。」 根據上文，下列選項何者正確？', '["施壓政府單位擬定友善無家者的政策", "協助無家者重返社會，打破流浪循環", "改善無家者居住環境與強化人身安全", "資助年輕人創業，改善青年失業問題"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:36+00:00", "source_pdf_sha1": "16c911fc4062", "answer_pdf_sha1": "ac5dd4608ec6", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "301", "s": "0103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL)
